# Update Firebase credential in .env.local
$envFile = ".env.local"
$content = Get-Content $envFile -Raw

# Firebase base64 credential
$firebaseB64 = ""

# Replace FIREBASE_ADMIN_SERVICE_ACCOUNT value
$content = $content -replace 'FIREBASE_ADMIN_SERVICE_ACCOUNT=.*', "FIREBASE_ADMIN_SERVICE_ACCOUNT=$firebaseB64"

# Save with UTF8 encoding without BOM
[System.IO.File]::WriteAllText((Resolve-Path $envFile), $content, (New-Object System.Text.UTF8Encoding($false)))

Write-Host "✅ Firebase credential updated in .env.local" -ForegroundColor Green
